    /* =========================================
       ROOT COLLAPSE BAR
       ========================================= */
    .pt-root-toggle {
        position: absolute;
        opacity: 0;
        pointer-events: none;
        width: 0;
        height: 0;
    }

    .pt-root-bar {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 12px 18px;
        cursor: pointer;
        user-select: none;
        position: relative;
        border-bottom: 1px solid transparent;
        transition: border-color 0.3s ease;
    }

    .pt-root-bar::after {
        content: &#039;&#039;;
        position: absolute;
        bottom: 0;
        left: 10%;
        width: 80%;
        height: 1px;
        background: linear-gradient(90deg, transparent, rgba(201, 166, 255, 0.2), transparent);
        opacity: 0.4;
        animation: barPulse 3s ease-in-out infinite;
    }

    .pt-root-toggle:checked ~ .pt-root-bar {
        border-bottom-color: rgba(255,255,255,0.06);
    }

    .pt-root-summary {
        display: flex;
        align-items: center;
        gap: 10px;
        font-size: 0.75rem;
        font-weight: 600;
        color: var(--pt-txt-dim);
        text-transform: uppercase;
        letter-spacing: 0.6px;
        z-index: 1;
    }

    .pt-root-summary .pt-accent-text {
        color: var(--pt-accent);
        font-weight: 700;
    }

    .pt-root-chevron {
        opacity: 0.4;
        transition: transform 0.5s cubic-bezier(0.2, 0.8, 0.2, 1);
        z-index: 1;
    }

    .pt-root-toggle:checked ~ .pt-root-bar .pt-root-chevron {
        transform: rotate(180deg);
        opacity: 1;
    }

    .pt-root-body {
        max-height: 0;
        overflow: hidden;
        transition: max-height 0.7s cubic-bezier(0.2, 0.8, 0.2, 1);
        will-change: max-height;
    }

    .pt-root-toggle:checked ~ .pt-root-body {
        max-height: 2400px;
    }

    .pt-root-inner {
        opacity: 0;
        transform: translate3d(0, -10px, 0);
        transition: opacity 0.35s ease, transform 0.35s ease;
    }

    .pt-root-toggle:checked ~ .pt-root-body .pt-root-inner {
        opacity: 1;
        transform: translate3d(0, 0, 0);
        transition-delay: 0.1s;
    }

    /* Subtle page meta line */
    .pt-page-meta {
        display: flex;
        align-items: center;
        gap: 8px;
        margin-bottom: 10px;
        font-size: 0.62rem;
        color: var(--pt-txt-dim);
        text-transform: uppercase;
        letter-spacing: 0.7px;
        font-weight: 600;
    }

    .pt-page-meta .pt-dot-sep {
        width: 3px;
        height: 3px;
        border-radius: 50%;
        background: rgba(255,255,255,0.15);
    }
